use agentschema::CodeConfiguration;


#[test]
fn test_code_configuration_load_json() {
    let json = r####"
{
  "runtime": "python_3_11",
  "entryPoint": "main.py",
  "dependencyResolution": "remote_build"
}
"####;
    let result = CodeConfiguration::from_json(json);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert_eq!(instance.runtime, "python_3_11");
    assert_eq!(instance.entry_point, "main.py");
    assert!(instance.dependency_resolution.is_some(), "Expected dependency_resolution to be Some");
    assert_eq!(instance.dependency_resolution.as_ref().unwrap(), &"remote_build");
}

